pub struct NatsPublisher {
    central_publisher: CentralEventPublisher,
    conn: Connection,
    subject_prefix: String,
}

impl NatsPublisher {
    pub async fn connect(
        nats_url: &str,
        jwt: Option<String>,
        prefix: impl Into<String>,
    ) -> Result<Self, PublishError> {
        let conn = if let Some(token) = jwt {
            asynk::Options::with_jwt(token, |nonce| async move {
                Ok(vec![])
            })
            .connect(nats_url)
            .await?
        } else {
            asynk::connect(nats_url).await?
        };

        Ok(Self {
            central_publisher: CentralEventPublisher::new(),
            conn,
            subject_prefix: prefix.into(),
        })
    }

    pub async fn publish(&self, event: &EventEnvelope) -> Result<(), PublishError> {
        // Use centralized publisher for serialization and common logic
        self.central_publisher.publish_to_topic(&event.event_type, event)
            .await
            .map_err(|e| match e {
                EventPublisherError::Serialization(e) => PublishError::Serde(e),
                _ => PublishError::Nats(nats::Error::new(nats::ErrorKind::Other, e.to_string())),
            })
    }
}
