   130→/// Wrapper persisted to the outbox and exchanged via NATS.
   131→///
   132→/// We store payload as raw JSON (`payload_json`) to avoid polymorphism issues
   133→/// in the DB layer while still enabling typed deserialization by consumers.
   134→#[derive(Debug, Serialize, Deserialize)]
   135→pub struct EventEnvelope {
   136→    pub id: Uuid,
   137→    pub aggregate_id: Uuid,
   138→    pub event_type: String,
   139→    pub event_version: u8,
   140→    pub occurred_at: DateTime<Utc>,
   141→
   142→    /// Raw JSON representation of the event.
   143→    pub payload_json: serde_json::Value,
   144→}
