   146→impl EventEnvelope {
   147→    /// Create a new envelope from a concrete [`DomainEvent`] implementation.
   148→    pub fn from_event<E: DomainEvent>(event: &E) -> serde_json::Result<Self> {
   149→        Ok(Self {
   150→            id: event.event_id(),
   151→            aggregate_id: event.aggregate_id(),
   152→            event_type: E::EVENT_TYPE.to_string(),
   153→            event_version: E::EVENT_VERSION,
   154→            occurred_at: event.occurred_at(),
   155→            payload_json: serde_json::to_value(event)?,
   156→        })
   157→    }
   158→}
