   163→
   164→#[derive(Debug, Error)]
   165→pub enum OutboxError {
   166→    #[error("Database error: {0}")]
   167→    Db(#[from] sqlx::Error),
   168→    #[error("Serde error: {0}")]
   169→    Serde(#[from] serde_json::Error),
   170→}
