   172→#[async_trait]
   173→pub trait EventOutboxRepository: Send + Sync {
   174→    /// Persist a new domain event within an existing DB transaction.
   175→    async fn add_event<E: DomainEvent + Send + Sync>(
   176→        &self,
   177→        tx: &mut sqlx::Transaction<'_, Postgres>,
   178→        event: &E,
   179→    ) -> Result<(), OutboxError>;
   180→
   181→    /// Fetch a *batch* of events that have not yet been dispatched.
   182→    async fn fetch_pending(
   183→        &self,
   184→        limit: i64,
   185→    ) -> Result<Vec<EventEnvelope>, OutboxError>;
   186→
   187→    /// Mark the given event IDs as dispatched.
   188→    async fn mark_dispatched(&self, ids: &[Uuid]) -> Result<(), OutboxError>;
   189→}
   190→
   191→/// PostgreSQL implementation of [`EventOutboxRepository`].
   192→pub struct PgOutboxRepository {
   193→    pool: PgPool,
   194→}
   195→
   196→impl PgOutboxRepository {
   197→    pub fn new(pool: PgPool) -> Self {
   198→        Self { pool }
   199→    }
   200→}
   201→
   202→#[async_trait]
   203→impl EventOutboxRepository for PgOutboxRepository {
   204→    #[instrument(skip(self, tx, event))]
   205→    async fn add_event<E: DomainEvent + Send + Sync>(
   206→        &self,
   207→        tx: &mut sqlx::Transaction<'_, Postgres>,
   208→        event: &E,
   209→    ) -> Result<(), OutboxError> {
   210→        let env = EventEnvelope::from_event(event)?;
   211→        sqlx::query!(
   212→            r#"
   213→            INSERT INTO outbox_events (
   214→                id,
   215→                aggregate_id,
   216→                event_type,
   217→                event_version,
   218→                occurred_at,
   219→                payload_json
   220→            )
   221→            VALUES ($1, $2, $3, $4, $5, $6)
   222→            "#,
   223→            env.id,
   224→            env.aggregate_id,
   225→            env.event_type,
   226→            env.event_version as i16,
   227→            env.occurred_at,
   228→            env.payload_json,
   229→        )
   230→        .execute(&mut **tx)
   231→        .await?;
   232→        Ok(())
   233→    }
   234→
   235→    #[instrument(skip(self))]
   236→    async fn fetch_pending(
   237→        &self,
   238→        limit: i64,
   239→    ) -> Result<Vec<EventEnvelope>, OutboxError> {
   240→        let raw = sqlx::query!(
   241→            r#"
   242→            SELECT id,
   243→                   aggregate_id,
   244→                   event_type,
   245→                   event_version,
   246→                   occurred_at,
   247→                   payload_json
   248→            FROM outbox_events
   249→            WHERE dispatched_at IS NULL
   250→            ORDER BY occurred_at
   251→            LIMIT $1
   252→            "#,
   253→            limit
   254→        )
   255→        .fetch_all(&self.pool)
   256→        .await?;
   257→
   258→        let mut events = Vec::with_capacity(raw.len());
   259→        for row in raw {
   260→            events.push(EventEnvelope {
   261→                id: row.id,
   262→                aggregate_id: row.aggregate_id,
   263→                event_type: row.event_type,
   264→                event_version: row.event_version as u8,
   265→                occurred_at: row.occurred_at,
   266→                payload_json: row.payload_json,
   267→            });
   268→        }
   269→        Ok(events)
   270→    }
   271→
   272→    #[instrument(skip(self, ids))]
   273→    async fn mark_dispatched(&self, ids: &[Uuid]) -> Result<(), OutboxError> {
   274→        if ids.is_empty() {
   275→            return Ok(());
   276→        }
   277→
   278→        let mut qb: QueryBuilder<Postgres> = QueryBuilder::new(
   279→            "UPDATE outbox_events SET dispatched_at = NOW() WHERE id IN (",
   280→        );
   281→        let mut separated = qb.separated(", ");
   282→        for id in ids {
   283→            separated.push_bind(id);
   284→        }
   285→        separated.push_unseparated(")");
   286→
   287→        qb.build().execute(&self.pool).await?;
   288→        Ok(())
   289→    }
   290→}
