   365→/// Repeatedly polls the outbox and hands events to the broker.
   366→///
   367→/// Spawn via [`tokio::spawn`]; it terminates when the passed `shutdown`
   368→/// [`tokio::sync::broadcast::Receiver`] is signalled.
   369→pub struct EventDispatcher<R: EventOutboxRepository, P: EventPublisher> {
   370→    repo: Arc<R>,
   371→    publisher: Arc<P>,
   372→    batch_size: i64,
   373→    poll_interval: Duration,
   374→}
   375→
   376→impl<R, P> EventDispatcher<R, P>
   377→where
   378→    R: EventOutboxRepository + 'static,
   379→    P: EventPublisher + 'static,
   380→{
   381→    pub fn new(
   382→        repo: Arc<R>,
   383→        publisher: Arc<P>,
   384→        batch_size: i64,
   385→        poll_interval: Duration,
   386→    ) -> Self {
   387→        Self {
   388→            repo,
   389→            publisher,
   390→            batch_size,
   391→            poll_interval,
   392→        }
   393→    }
   394→
   395→    #[instrument(skip(self, shutdown_rx), name = "event_dispatch_loop")]
   396→    pub fn start(
   397→        self,
   398→        mut shutdown_rx: tokio::sync::broadcast::Receiver<()>,
   399→    ) -> JoinHandle<()> {
   400→        tokio::spawn(async move {
   401→            loop {
   402→                select! {
   403→                    _ = shutdown_rx.recv() => {
   404→                        info!("EventDispatcher received shutdown signal");
   405→                        break;
   406→                    }
   407→                    _ = self.tick() => {}
   408→                }
   409→            }
   410→        })
   411→    }
   412→
   413→    /// Single poll → publish → ack iteration.
   414→    async fn tick(&self) {
   415→        match self
   416→            .repo
   417→            .fetch_pending(self.batch_size)
   418→            .await
   419→        {
   420→            Ok(events) if events.is_empty() => {
   421→                sleep(self.poll_interval).await;
   422→            }
   423→            Ok(events) => {
   424→                let ids: Vec<Uuid> = events.iter().map(|e| e.id).collect();
   425→                debug!(count = events.len(), "Publishing events");
   426→
   427→                // Publish concurrently but limit concurrency to avoid backpressure.
   428→                let results = stream::iter(events)
   429→                    .map(|e| async {
   430→                        if let Err(err) = self.publisher.publish(&e).await {
   431→                            error!(error = %err, "Failed to publish event");
   432→                            Err(err)
   433→                        } else {
   434→                            Ok(())
   435→                        }
   436→                    })
   437→                    .buffer_unordered(8)
   438→                    .collect::<Vec<_>>()
   439→                    .await;
   440→
   441→                if results.iter().all(Result::is_ok) {
   442→                    if let Err(err) = self.repo.mark_dispatched(&ids).await {
   443→                        error!(%err, "Failed to mark events as dispatched");
   444→                    }
   445→                } else {
   446→                    warn!("Some events failed to publish; will retry later");
   447→                }
   448→            }
