    71→/// This allows fault-tolerant, ordered replay while keeping the event payload
    72→/// opaque to the infrastructure layer.
    73→#[derive(Debug, Clone, Serialize, Deserialize)]
    74→pub struct EventEnvelope {
    75→    pub id: Uuid,
    76→    pub aggregate_id: Uuid,
    77→    pub occurred_at: DateTime<Utc>,
    78→    pub event: DomainEvent,
