    81→/// Database representation of an outbox message.
    82→///
    83→/// The table is expected to look like:
    84→///
    85→/// ```sql
    86→/// CREATE TABLE outbox (
    87→///     id              uuid      PRIMARY KEY,
    88→///     aggregate_id    uuid      NOT NULL,
    89→///     event_type      text      NOT NULL,
    90→///     payload         jsonb     NOT NULL,
    91→///     occurred_at     timestamptz NOT NULL,
    92→///     retries         smallint     NOT NULL DEFAULT 0,
    93→///     locked_until    timestamptz,
    94→///     delivered_at    timestamptz
