    96→/// CREATE INDEX idx_outbox_retries ON outbox (retries);
    97→/// CREATE INDEX idx_outbox_pending ON outbox (delivered_at) WHERE delivered_at IS NULL;
    98→/// ```
    99→#[derive(Debug, Clone)]
   100→struct OutboxRow {
   101→    id: Uuid,
   102→    aggregate_id: Uuid,
   103→    event_type: String,
   104→    payload: serde_json::Value,
   105→    occurred_at: DateTime<Utc>,
   106→    retries: i16,
