   113→            DomainEvent::PulseCreated { .. } => "PulseCreated",
   114→            DomainEvent::PulseAnswered { .. } => "PulseAnswered",
   115→            DomainEvent::BadgeAwarded { .. } => "BadgeAwarded",
   116→        }
   117→        .to_string();
