   119→        Ok(Self {
   120→            id: envelope.id,
   121→            aggregate_id: envelope.aggregate_id,
   122→            event_type,
   123→            payload: serde_json::to_value(&envelope.event)?,
   124→            occurred_at: envelope.occurred_at,
   125→            retries: 0,
   126→        })
   127→    }
   128→}
