   130→/// Errors originating in the outbox layer.
   131→#[derive(Debug, Error)]
   132→pub enum OutboxError {
   133→    #[error("Persistence failure: {0}")]
   134→    Persistence(#[from] sqlx::Error),
   135→
   136→    #[error("Serialization failure: {0}")]
   137→    Serialization(#[from] serde_json::Error),
   138→
   139→    #[error("Channel closed")]
   140→    ChannelClosed,
   141→}
