   143→/// Abstraction over anything that can store events in the outbox.
   144→#[async_trait]
   145→pub trait OutboxRepository {
   146→    async fn save(
   147→        &self,
   148→        tx: &mut Transaction<'_, Postgres>,
   149→        envelope: EventEnvelope,
   150→    ) -> Result<(), OutboxError>;
