   153→/// PostgreSQL implementation of the outbox repository.
   154→pub struct PgOutboxRepository {
   155→    pool: PgPool,
   156→}
   157→
   158→impl PgOutboxRepository {
   159→    pub fn new(pool: PgPool) -> Self {
   160→        Self { pool }
   161→    }
   162→}
   163→
   164→#[async_trait]
   165→impl OutboxRepository for PgOutboxRepository {
   166→    #[instrument(level = "debug", skip_all, fields(event_id=%envelope.id))]
   167→    async fn save(
   168→        &self,
   169→        tx: &mut Transaction<'_, Postgres>,
   170→        envelope: EventEnvelope,
   171→    ) -> Result<(), OutboxError> {
   172→        let row = OutboxRow::from_envelope(envelope)?;
   173→        query!(
   174→            r#"
   175→            INSERT INTO outbox (id, aggregate_id, event_type, payload, occurred_at)
   176→            VALUES ($1, $2, $3, $4, $5)
   177→            "#,
   178→            row.id,
   179→            row.aggregate_id,
   180→            row.event_type,
   181→            row.payload,
   182→            row.occurred_at,
   183→        )
   184→        .execute(&mut *tx)
   185→        .await?;
   186→
   187→        Ok(())
   188→    }
   189→}
   190→
   191→/// Contract for anything that can publish events from the outbox to an external
   192→/// broker (NATS, RabbitMQ, Kafka, …).
   193→#[async_trait]
   194→pub trait EventPublisher {
   195→    async fn publish(&self, envelope: EventEnvelope) -> Result<(), anyhow::Error>;
   196→}
