     2→//! Integration‐style tests for the “EduPulse Live” social learning hub.
     3→//!
     4→//! The real application is a large, event-driven distributed system.  In these
     5→//! tests we spin up **in-memory stand-ins** for some of the platform’s core
     6→//! services (event bus, authentication/session management, analytics) and make
     7→//! sure that the public behaviour—the contract—matches expectations.
     8→//!
     9→//! The code in this file is fully self-contained so that it can compile and run
    10→//! without the rest of the production crate being present.  In the real
    11→//! code-base each component would live in its own module/crate and expose a
    12→//! clear interface.
    13→
    14→// Std-lib imports ------------------------------------------------------------
    15→use std::{
    16→    collections::{HashMap, HashSet},
    17→    fmt,
    18→    sync::{
    19→        atomic::{AtomicBool, Ordering},
    20→        mpsc::{self, Receiver, Sender},
    21→        Arc, Mutex,
    22→    },
    23→    thread,
    24→    time::{Duration, SystemTime, UNIX_EPOCH},
    25→};
    26→
    27→// ─────────────────────────────────────────────────────────────────────────────
    28→// Domain events
    29→// ─────────────────────────────────────────────────────────────────────────────
    30→
    31→/// All significant state changes inside EduPulse Live emit a DomainEvent.
    32→#[derive(Debug, Clone)]
    33→enum DomainEvent {
    34→    LessonPublished {
    35→        lesson_id: u64,
    36→        title: String,
    37→    },
    38→    PulseReplied {
    39→        user_id: u64,
    40→        pulse_id: u64,
    41→        reply: String,
    42→    },
    43→    UserLoggedIn {
    44→        user_id: u64,
    45→        session_token: String,
    46→    },
    47→}
    48→
    49→/// Basic error type for the EventBus.
    50→#[derive(Debug)]
    51→enum BusError {
    52→    PublishFailed,
    53→}
    54→
    55→impl fmt::Display for BusError {
    56→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
    57→        match self {
    58→            BusError::PublishFailed => write!(f, "unable to publish event"),
    59→        }
    60→    }
    61→}
    62→
    63→// ─────────────────────────────────────────────────────────────────────────────
    64→// In-memory EventBus (fan-out)
    65→// ─────────────────────────────────────────────────────────────────────────────
    66→
    67→/// Very small, in-process, fan-out event bus used exclusively for testing.
    68→///
    69→/// Every call to `subscribe()` registers a new channel (Sender) that will
    70→/// receive a **copy** of every published DomainEvent.  Publication errors are
    71→/// silently swallowed by individual subscribers so that one slow consumer
    72→/// never blocks the rest.
    73→#[derive(Clone, Default)]
    74→struct EventBus {
    75→    subscribers: Arc<Mutex<Vec<Sender<DomainEvent>>>>,
    76→}
    77→
    78→impl EventBus {
    79→    /// Create a fresh, empty bus.
    80→    fn new() -> Self {
    81→        Self::default()
    82→    }
    83→
    84→    /// Publish an event to all currently active subscribers.
    85→    fn publish(&self, event: DomainEvent) -> Result<(), BusError> {
    86→        let subs = self
    87→            .subscribers
    88→            .lock()
    89→            .expect("poisoned subscriber list in EventBus");
    90→
    91→        for tx in subs.iter() {
    92→            // Ignore per-subscriber errors; fire-and-forget semantics.
    93→            let _ = tx.send(event.clone());
    94→        }
    95→        Ok(())
    96→    }
    97→
    98→    /// Register a new subscriber and get the receiving end of its channel.
    99→    fn subscribe(&self) -> Receiver<DomainEvent> {
   100→        let (tx, rx) = mpsc::channel();
   101→
   102→        self.subscribers
   103→            .lock()
   104→            .expect("poisoned subscriber list in EventBus")
   105→            .push(tx);
   106→
   107→        rx
   108→    }
   109→}
   110→
   111→// ─────────────────────────────────────────────────────────────────────────────
   112→// Authentication & session handling
   113→// ─────────────────────────────────────────────────────────────────────────────
   114→
   115→/// Errors produced by `AuthService`.
   116→#[derive(Debug)]
   117→enum AuthError {
   118→    UnknownUser,
   119→    TokenCollision,
   120→}
   121→
   122→impl fmt::Display for AuthError {
   123→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
   124→        match self {
   125→            AuthError::UnknownUser => write!(f, "user not found"),
   126→            AuthError::TokenCollision => write!(f, "session-token collision"),
   127→        }
   128→    }
   129→}
   130→
   131→/// Thread-safe, in-memory authentication service used in tests.
   132→#[derive(Debug, Default)]
   133→struct AuthService {
   134→    // In production this would be a database call via a repository.
   135→    registered_users: HashSet<u64>,
   136→
   137→    // session_token -> user_id
   138→    sessions: Mutex<HashMap<String, u64>>,
   139→}
   140→
   141→impl AuthService {
   142→    fn new(registered_users: &[u64]) -> Self {
   143→        Self {
   144→            registered_users: registered_users.iter().copied().collect(),
   145→            sessions: Mutex::new(HashMap::new()),
   146→        }
   147→    }
   148→
   149→    /// Log the given user in and produce a fresh session token.
   150→    ///
   151→    /// A DomainEvent is emitted on success.
   152→    fn login(
   153→        &self,
   154→        user_id: u64,
   155→        bus: &EventBus,
   156→    ) -> Result<String, AuthError> {
   157→        if !self.registered_users.contains(&user_id) {
   158→            return Err(AuthError::UnknownUser);
   159→        }
   160→
   161→        let token = Self::generate_token(user_id);
   162→
   163→        let mut guard = self.sessions.lock().expect("poisoned session map");
   164→        if guard.contains_key(&token) {
   165→            // Unlikely, but should never overwrite another session.
   166→            return Err(AuthError::TokenCollision);
   167→        }
   168→        guard.insert(token.clone(), user_id);
   169→        drop(guard); // Explicitly drop lock before we publish an event.
   170→
   171→        bus.publish(DomainEvent::UserLoggedIn {
   172→            user_id,
   173→            session_token: token.clone(),
   174→        })
   175→        .expect("event bus must live for the entire test run");
   176→
   177→        Ok(token)
   178→    }
   179→
   180→    /// Very naive, deterministic “random” token generator for test purposes.
   181→    fn generate_token(user_id: u64) -> String {
   182→        let epoch_millis = SystemTime::now()
   183→            .duration_since(UNIX_EPOCH)
   184→            .expect("system time before 1970?")
   185→            .as_millis();
   186→
   187→        format!("{user_id:x}-{epoch_millis:x}")
   188→    }
   189→}
   190→
   191→// ─────────────────────────────────────────────────────────────────────────────
   192→// Analytics service (consumer)
   193→// ─────────────────────────────────────────────────────────────────────────────
   194→
   195→/// Simple analytics worker.  In production this would run in its own process
   196→/// and push data into a columnar store; in tests we only count events.
   197→struct AnalyticsService {
   198→    processed_pulse_replies: Arc<AtomicBool>,
   199→}
   200→
   201→impl AnalyticsService {
   202→    fn new() -> (Self, Arc<AtomicBool>) {
   203→        let flag = Arc::new(AtomicBool::new(false));
   204→        let svc = Self {
   205→            processed_pulse_replies: flag.clone(),
   206→        };
   207→        (svc, flag)
   208→    }
   209→
   210→    /// Start an **owned** worker thread that listens for events until the
   211→    /// supplied `shutdown_rx` channel is closed.
   212→    fn start(self, bus_rx: Receiver<DomainEvent>, shutdown_rx: Receiver<()>) {
   213→        thread::spawn(move || {
   214→            loop {
   215→                // prefer shutdown over event—non-blocking check
   216→                if let Ok(_) = shutdown_rx.try_recv() {
   217→                    break;
   218→                }
   219→                match bus_rx.recv_timeout(Duration::from_millis(100)) {
   220→                    Ok(event) => self.handle_event(event),
   221→                    Err(mpsc::RecvTimeoutError::Timeout) => continue,
   222→                    Err(mpsc::RecvTimeoutError::Disconnected) => break,
   223→                }
   224→            }
   225→        });
   226→    }
   227→
   228→    fn handle_event(&self, ev: DomainEvent) {
   229→        match ev {
   230→            DomainEvent::PulseReplied { .. } => {
   231→                self.processed_pulse_replies
   232→                    .store(true, Ordering::SeqCst);
   233→            }
   234→            _ => {} // ignore all other events
   235→        }
   236→    }
   237→}
   238→
   239→// ─────────────────────────────────────────────────────────────────────────────
   240→// Tests
   241→// ─────────────────────────────────────────────────────────────────────────────
   242→
   243→/// Make sure that a PulseReplied event is observed by the analytics worker.
   244→#[test]
   245→fn pulse_reply_is_forwarded_to_analytics_service() {
   246→    // Arrange
   247→    let bus = EventBus::new();
   248→
   249→    // Channel to allow clean shutdown when the test finishes.
   250→    let (shutdown_tx, shutdown_rx) = mpsc::channel();
   251→
   252→    // Subscriber and worker bootstrap
   253→    let bus_rx = bus.subscribe();
   254→    let (analytics_service, processed_flag) = AnalyticsService::new();
   255→    analytics_service.start(bus_rx, shutdown_rx);
   256→
   257→    // Act
   258→    bus.publish(DomainEvent::PulseReplied {
   259→        user_id: 42,
   260→        pulse_id: 7,
   261→        reply: "Here is my work…".into(),
   262→    })
   263→    .expect("failed to publish event");
   264→
   265→    // Give the worker up to 2 seconds real time.
   266→    for _ in 0..20 {
   267→        if processed_flag.load(Ordering::SeqCst) {
   268→            break;
   269→        }
   270→        thread::sleep(Duration::from_millis(100));
   271→    }
   272→
   273→    // Clean shutdown
   274→    let _ = shutdown_tx.send(());
   275→
   276→    // Assert
   277→    assert!(
   278→        processed_flag.load(Ordering::SeqCst),
   279→        "analytics worker never saw PulseReplied event"
   280→    );
   281→}
   282→
   283→/// Verify that a successful login creates a session and emits the right event.
   284→#[test]
   285→fn successful_login_creates_session_and_emits_event() {
   286→    // Arrange
   287→    let bus = EventBus::new();
   288→    let rx = bus.subscribe();
   289→
   290→    let auth = AuthService::new(&[1, 2, 3]); // user 1 is registered
   291→
   292→    // Act
   293→    let token = auth
   294→        .login(1, &bus)
   295→        .expect("login should succeed for registered user");
   296→
   297→    // Assert token shape (very coarse sanity check)
   298→    assert!(
   299→        token.starts_with("1-"),
   300→        "unexpected token format: {token:?}"
   301→    );
   302→
   303→    // The next event on the bus must be our login.
   304→    let event =
   305→        rx.recv_timeout(Duration::from_secs(1)).expect("no event received");
   306→
   307→    match event {
   308→        DomainEvent::UserLoggedIn {
   309→            user_id,
   310→            session_token,
   311→        } => {
   312→            assert_eq!(user_id, 1);
   313→            assert_eq!(session_token, token);
   314→        }
   315→        other => panic!("unexpected event: {other:?}"),
   316→    }
   317→}
   318→
   319→/// Attempting to log in with an unknown user should be rejected.
   320→#[test]
   321→fn unknown_user_cannot_log_in() {
   322→    let bus = EventBus::new();
   323→    let auth = AuthService::new(&[99]); // only user 99 exists
