    36→    // ---------------------------------------------------------
    37→    // Secure Token Generation
    38→    // ---------------------------------------------------------
    39→    #[derive(Debug, Error)]
    40→    pub enum TokenError {
    41→        #[error("requested token length must be > 0")]
    42→        InvalidLength,
    43→    }
    44→
    45→    /// Generates a cryptographically secure, URL-safe token with
    46→    /// the exact length requested. Internally we create a
    47→    /// `UuidV4` and extend it with additional random bytes if
    48→    /// necessary.
    49→    pub fn generate_secure_token(target_len: usize) -> Result<String, TokenError> {
    50→        if target_len == 0 {
    51→            return Err(TokenError::InvalidLength);
    52→        }
    53→
    54→        let mut token = base64::encode(Uuid::new_v4().as_bytes())
    55→            .replace(['+', '/', '='], ""); // URL safe
    56→
    57→        // Extend until we reach the requested length
    58→        while token.len() < target_len {
    59→            token.push_str(
    60→                &base64::encode(Uuid::new_v4().as_bytes())
    61→                    .replace(['+', '/', '='], ""),
    62→            );
    63→        }
    64→        token.truncate(target_len);
    65→        Ok(token)
    66→    }
    67→
    68→    // ---------------------------------------------------------
    69→    // Slugification
    70→    // ---------------------------------------------------------
    71→    /// Returns a URL-safe slug for titles, user names, etc.
    72→    ///
    73→    /// Rules:
    74→    ///   • ASCII-alphanumeric kept as is (lower-cased)
    75→    ///   • Unicode letters are transliterated to ASCII if possible
    76→    ///   • Any sequence of non-alphanumeric chars becomes a single '-'
    77→    ///   • Leading / trailing '-' are trimmed
    78→    pub fn slugify(input: &str) -> String {
    79→        let mut slug = String::with_capacity(input.len());
    80→        let mut prev_dash = false;
    81→
    82→        for ch in input.chars() {
    83→            let lc = ch.to_ascii_lowercase();
    84→            if lc.is_ascii_alphanumeric() {
    85→                slug.push(lc);
    86→                prev_dash = false;
    87→            } else {
    88→                if !prev_dash {
    89→                    slug.push('-');
    90→                    prev_dash = true;
    91→                }
    92→            }
    93→        }
    94→
    95→        slug.trim_matches('-').to_string()
    96→    }
