    98→    // ---------------------------------------------------------
    99→    // Event Schema Validation
   100→    // ---------------------------------------------------------
   101→    #[derive(Debug, Deserialize, Serialize, PartialEq, Eq)]
   102→    pub struct Event<'a> {
   103→        pub id: Uuid,
   104→        #[serde(rename = "type")]
   105→        pub event_type: &'a str,
   106→        pub version: u16,
   107→        #[serde(with = "chrono::serde::ts_milliseconds")]
   108→        pub created_at: DateTime<Utc>,
   109→    }
   110→
   111→    #[derive(Debug, Error)]
   112→    pub enum EventValidationError {
   113→        #[error("payload is not valid JSON: {0}")]
   114→        JsonError(#[from] serde_json::Error),
   115→        #[error("field 'version' must be greater than 0")]
   116→        InvalidVersion,
   117→        #[error("'id' field is not a valid UUID")]
   118→        InvalidId,
   119→        #[error("event type must be non-empty")]
   120→        EmptyEventType,
   121→        #[error("duplicate event id")]
   122→        DuplicateId,
   123→    }
   124→
   125→    /// Parses a JSON payload into an `Event` and performs
   126→    /// additional domain-specific validation such as:
   127→    ///   • `version` must be > 0
   128→    ///   • `event_type` must not be empty
   129→    ///   • UUID must be valid
   130→    ///   • Id must be unique within the provided `seen_ids` set
   131→    pub fn verify_event_schema<'a>(
   132→        payload: &'a str,
   133→        seen_ids: &mut HashSet<Uuid>,
   134→    ) -> Result<Event<'a>, EventValidationError> {
   135→        let evt: Event<'a> = serde_json::from_str(payload)?;
   136→        if evt.version == 0 {
   137→            return Err(EventValidationError::InvalidVersion);
   138→        }
   139→        if evt.event_type.trim().is_empty() {
   140→            return Err(EventValidationError::EmptyEventType);
   141→        }
   142→        // UUID validity is already enforced by serde + Uuid but
   143→        // we add an explicit check for completeness.
   144→        Uuid::from_str(evt.id.as_hyphenated().to_string().as_str())
   145→            .map_err(|_| EventValidationError::InvalidId)?;
   146→
   147→        if !seen_ids.insert(evt.id) {
   148→            return Err(EventValidationError::DuplicateId);
   149→        }
   150→
   151→        Ok(evt)
   152→    }
   153→}
