   162→#[test]
   163→fn test_secure_token_length_and_uniqueness() {
   164→    const TOKEN_LEN: usize = 32;
   165→    const RUNS: usize = 1_000;
   166→
   167→    let mut unique = std::collections::HashSet::with_capacity(RUNS);
   168→    for _ in 0..RUNS {
   169→        let token = generate_secure_token(TOKEN_LEN).expect("token generation failed");
   170→        assert_eq!(
   171→            token.len(),
   172→            TOKEN_LEN,
   173→            "generated token does not match requested length"
   174→        );
   175→        // Make sure token is URL-safe
   176→        assert!(
   177→            token.chars()
   178→                .all(|c| c.is_ascii_alphanumeric() || c == '-' || c == '_'),
   179→            "token contains non-URL-safe characters"
   180→        );
   181→        unique.insert(token);
   182→    }
   183→
   184→    assert_eq!(
   185→        unique.len(),
   186→        RUNS,
   187→        "expected all generated tokens to be unique"
   188→    );
   189→}
