/// Centralized event publisher for the EduPulse Live platform.
///
/// This struct manages the event bus configuration and provides a single,
/// generic method for publishing events of any serializable type.
///
/// # Thread Safety
///
/// `EventPublisher` is `Send + Sync` and can be safely shared across threads
/// using `Arc<EventPublisher>`.
#[derive(Debug, Clone)]
pub struct EventPublisher {
    config: EventBusConfig,
}

impl EventPublisher {
    /// Creates a new `EventPublisher` instance.
    ///
    /// Retrieves configuration from the `get_event_bus_config()` function
    /// in `crate::utils`, which reads from environment variables or uses
    /// sensible defaults.
    ///
    /// # Example
    ///
    /// ```rust,no_run
    /// let publisher = EventPublisher::new();
    /// ```
    pub fn new() -> Self {
        let config = get_event_bus_config();
        Self { config }
    }

    /// Creates a new `EventPublisher` with a custom configuration.
    ///
    /// This is useful for testing or when you need to override the default
    /// configuration.
    pub fn with_config(config: EventBusConfig) -> Self {
        Self { config }
    }

    /// Publishes an event payload to the event stream.
    ///
    /// This method handles:
    /// - Serialization of the payload to JSON
    /// - Sending the serialized event to the event stream
    /// - Error handling and propagation
    ///
    /// # Type Parameters
    ///
    /// * `T` - The event payload type. Must implement `Serialize` and `Sync`.
    ///
    /// # Arguments
    ///
    /// * `payload` - A reference to the event payload to publish.
    ///
    /// # Returns
    ///
    /// Returns `Ok(())` if the event was successfully published, or an
    /// `EventPublisherError` if serialization or sending failed.
    ///
    /// # Example
    ///
    /// ```rust,no_run
    /// use serde::Serialize;
    ///
    /// #[derive(Serialize)]
    /// struct UserLoggedIn {
    ///     user_id: u64,
    ///     timestamp: i64,
    /// }
    ///
    /// async fn publish_login(publisher: &EventPublisher, user_id: u64) -> Result<(), EventPublisherError> {
    ///     let event = UserLoggedIn {
    ///         user_id,
    ///         timestamp: chrono::Utc::now().timestamp(),
    ///     };
    ///     publisher.publish(&event).await
    /// }
    /// ```
    pub async fn publish<T: Serialize + Sync>(&self, payload: &T) -> Result<(), EventPublisherError> {
        // Serialize the payload to JSON
        let json_payload = serde_json::to_string(payload)?;

        // Determine the topic based on the config
        let topic = format!("{}.events", self.config.topic_prefix);

        // Send the event to the stream
        send_event_to_stream(&self.config, &topic, &json_payload).await?;

        tracing::debug!(
            topic = %topic,
            payload_size = json_payload.len(),
            "Event published successfully"
        );

        Ok(())
    }

    /// Publishes an event payload to a specific topic on the event stream.
    ///
    /// This variant allows specifying a custom topic name, which is useful
    /// when different event types should be routed to different topics.
    ///
    /// # Arguments
    ///
    /// * `topic` - The topic name to publish to.
    /// * `payload` - A reference to the event payload to publish.
    ///
    /// # Returns
    ///
    /// Returns `Ok(())` if the event was successfully published, or an
    /// `EventPublisherError` if serialization or sending failed.
    pub async fn publish_to_topic<T: Serialize + Sync>(
        &self,
        topic: &str,
        payload: &T,
    ) -> Result<(), EventPublisherError> {
        // Serialize the payload to JSON
        let json_payload = serde_json::to_string(payload)?;

        // Build the full topic path
        let full_topic = format!("{}.{}", self.config.topic_prefix, topic);

        // Send the event to the stream
        send_event_to_stream(&self.config, &full_topic, &json_payload).await?;

        tracing::debug!(
            topic = %full_topic,
            payload_size = json_payload.len(),
            "Event published successfully"
        );

        Ok(())
    }

    /// Returns a reference to the current configuration.
    pub fn config(&self) -> &EventBusConfig {
        &self.config
    }
}

impl Default for EventPublisher {
    fn default() -> Self {
        Self::new()
    }
}

