//! src/event_publisher.rs
//!
//! Centralized Event Publishing Service for EduPulse Live
//! =======================================================
//!
//! This module provides a unified, generic event publishing service that
//! consolidates the previously scattered event publishing logic from various
//! modules (module_15, module_48, module_77). It eliminates code duplication
//! related to event serialization, connection handling, and error management.

use serde::Serialize;
use thiserror::Error;

use crate::utils::event_bus::{get_event_bus_config, send_event_to_stream, EventBusConfig, EventStreamError};

/// Errors that can occur during event publishing.
///
/// This enum consolidates all error cases from the previously scattered
/// event publishing implementations across different modules.
#[derive(Debug, Error)]
pub enum EventPublisherError {
    /// Failed to serialize the event payload to JSON.
    #[error("Serialization error: {0}")]
    Serialization(#[from] serde_json::Error),

    /// Failed to connect to the event bus.
    #[error("Connection error: {0}")]
    Connection(String),

    /// Failed to send the event to the stream.
    #[error("Send error: {0}")]
    Send(String),

    /// Operation timed out.
    #[error("Timeout after {0}ms")]
    Timeout(u64),
}

impl From<EventStreamError> for EventPublisherError {
    fn from(err: EventStreamError) -> Self {
        match err {
            EventStreamError::ConnectionFailed(msg) => EventPublisherError::Connection(msg),
            EventStreamError::SendFailed(msg) => EventPublisherError::Send(msg),
            EventStreamError::Timeout(ms) => EventPublisherError::Timeout(ms),
        }
    }
}

/// Centralized event publisher for the EduPulse Live platform.
///
/// This struct manages the event bus configuration and provides a single,
/// generic method for publishing events of any serializable type.
#[derive(Debug, Clone)]
pub struct EventPublisher {
    config: EventBusConfig,
}

impl EventPublisher {
    /// Creates a new `EventPublisher` instance.
    ///
    /// Retrieves configuration from the `get_event_bus_config()` function
    /// in `crate::utils::event_bus`.
    pub fn new() -> Self {
        let config = get_event_bus_config();
        Self { config }
    }

    /// Creates a new `EventPublisher` with a custom configuration.
    pub fn with_config(config: EventBusConfig) -> Self {
        Self { config }
    }

    /// Publishes an event payload to the event stream.
    ///
    /// This method handles:
    /// - Serialization of the payload to JSON
    /// - Sending the serialized event to the event stream
    /// - Error handling and propagation
    ///
    /// # Type Parameters
    ///
    /// * `T` - The event payload type. Must implement `Serialize` and `Sync`.
    pub async fn publish<T: Serialize + Sync>(&self, payload: &T) -> Result<(), EventPublisherError> {
        // Serialize the payload to JSON
        let json_payload = serde_json::to_string(payload)?;

        // Determine the topic based on the config
        let topic = format!("{}.events", self.config.topic_prefix);

        // Send the event to the stream
        send_event_to_stream(&self.config, &topic, &json_payload).await?;

        tracing::debug!(
            topic = %topic,
            payload_size = json_payload.len(),
            "Event published successfully"
        );

        Ok(())
    }

    /// Publishes an event payload to a specific topic on the event stream.
    pub async fn publish_to_topic<T: Serialize + Sync>(
        &self,
        topic: &str,
        payload: &T,
    ) -> Result<(), EventPublisherError> {
        let json_payload = serde_json::to_string(payload)?;
        let full_topic = format!("{}.{}", self.config.topic_prefix, topic);
        send_event_to_stream(&self.config, &full_topic, &json_payload).await?;

        tracing::debug!(
            topic = %full_topic,
            payload_size = json_payload.len(),
            "Event published successfully"
        );

        Ok(())
    }

    /// Returns a reference to the current configuration.
    pub fn config(&self) -> &EventBusConfig {
        &self.config
    }
}

impl Default for EventPublisher {
    fn default() -> Self {
        Self::new()
    }
}

